import{_ as a,o as r,c as e,ak as d}from"./chunks/framework.DwHlt8HN.js";const m=JSON.parse('{"title":"性能优化方法论","description":"","frontmatter":{},"headers":[],"relativePath":"high-performance/method/index.md","filePath":"high-performance/method/index.md","lastUpdated":1774360456000}'),h={name:"high-performance/method/index.md"};function i(l,t,n,o,s,p){return r(),e("div",null,[...t[0]||(t[0]=[d('<h1 id="性能优化方法论" tabindex="-1">性能优化方法论 <a class="header-anchor" href="#性能优化方法论" aria-label="Permalink to “性能优化方法论”">​</a></h1><p>你有没有过这样的经历：系统性能出问题了，你凭感觉加缓存、加机器、调参数，忙活了半天，效果却微乎其微。</p><p>而隔壁工位的同事，三下五除二就定位到了瓶颈，改了几行代码，系统性能直接翻倍。</p><p>差距在哪里？<strong>差距不在于你不够努力，而在于你缺少一套系统的方法论。</strong></p><p>性能优化不是玄学，也不是碰运气。它是一门讲究方法的工程学科。测量驱动找到瓶颈，木桶原理定位短板，循序渐进优化——掌握这套方法论，你也能成为团队里的「性能大师」。</p><p>本模块涵盖性能优化的核心思想、度量指标、瓶颈分析方法论、性能优化 checklist，以及全链路压测的实战技巧。</p><hr><h2 id="模块速览" tabindex="-1">模块速览 <a class="header-anchor" href="#模块速览" aria-label="Permalink to “模块速览”">​</a></h2><table tabindex="0"><thead><tr><th>文档</th><th>简介</th></tr></thead><tbody><tr><td><a href="/high-performance/method/principle">性能优化核心思想</a></td><td>木桶原理、边际效应、测量驱动的优化理念</td></tr><tr><td><a href="/high-performance/method/metrics">度量指标体系</a></td><td>延迟、吞吐量、资源利用率的核心指标</td></tr><tr><td><a href="/high-performance/method/bottleneck">瓶颈分析方法论</a></td><td>CPU、内存、IO、网络瓶颈的识别技巧</td></tr><tr><td><a href="/high-performance/method/pressure-test">全链路压测实战</a></td><td>从单点到全链路的压测方案</td></tr><tr><td><a href="/high-performance/method/checklist">性能优化 Checklist</a></td><td>各模块优化要点汇总</td></tr></tbody></table><hr><h2 id="为什么方法论比工具更重要" tabindex="-1">为什么方法论比工具更重要？ <a class="header-anchor" href="#为什么方法论比工具更重要" aria-label="Permalink to “为什么方法论比工具更重要？”">​</a></h2><p>很多人遇到性能问题时，第一反应是「加机器」或者「加缓存」。但真正的性能优化，始于<strong>测量驱动</strong>——先找到瓶颈在哪，再对症下药。</p><p>你遇到过这种情况吗？</p><ul><li>优化了半天的 SQL，结果发现瓶颈根本不在数据库，而在 GC 停顿</li><li>调整了 GC 参数，结果发现瓶颈是代码里一个被忽略的 <code>synchronized</code> 热点</li><li>加了三层缓存，结果发现缓存命中率只有 30%，纯属浪费</li></ul><p>这就是为什么方法论比工具更重要。<strong>木桶原理告诉我们：系统的性能取决于最短的那块木板。</strong> 只有先识别出瓶颈，优化才能事半功倍。</p><hr><h2 id="性能优化的正确姿势" tabindex="-1">性能优化的正确姿势 <a class="header-anchor" href="#性能优化的正确姿势" aria-label="Permalink to “性能优化的正确姿势”">​</a></h2><h3 id="第一步-建立度量体系" tabindex="-1">第一步：建立度量体系 <a class="header-anchor" href="#第一步-建立度量体系" aria-label="Permalink to “第一步：建立度量体系”">​</a></h3><p>没有度量，就没有优化。你需要关注三类核心指标：</p><ul><li><strong>延迟</strong>：P50、P95、P99 响应时间，决定用户体验</li><li><strong>吞吐量</strong>：QPS、TPS，反映系统处理能力</li><li><strong>资源利用率</strong>：CPU、内存、磁盘、网络的使用情况</li></ul><h3 id="第二步-定位瓶颈" tabindex="-1">第二步：定位瓶颈 <a class="header-anchor" href="#第二步-定位瓶颈" aria-label="Permalink to “第二步：定位瓶颈”">​</a></h3><p>常见的性能瓶颈有四大类：</p><table tabindex="0"><thead><tr><th>瓶颈类型</th><th>典型特征</th><th>排查工具</th></tr></thead><tbody><tr><td>CPU 瓶颈</td><td>CPU 使用率高、上下文切换频繁</td><td>top、vmstat、Arthas</td></tr><tr><td>内存瓶颈</td><td>OOM、GC 频繁、内存泄漏</td><td>jmap、MAT、Arthas</td></tr><tr><td>IO 瓶颈</td><td>磁盘繁忙、IO 等待高</td><td>iostat、iotop</td></tr><tr><td>网络瓶颈</td><td>连接超时、带宽耗尽</td><td>netstat、tcpdump</td></tr></tbody></table><h3 id="第三步-分析根因" tabindex="-1">第三步：分析根因 <a class="header-anchor" href="#第三步-分析根因" aria-label="Permalink to “第三步：分析根因”">​</a></h3><p>找到瓶颈后，不要急于动手。先问自己三个问题：</p><ol><li><strong>瓶颈的根因是什么？</strong> 是配置问题、代码问题，还是架构问题？</li><li><strong>优化的代价有多大？</strong> 需要改多少代码？风险有多高？</li><li><strong>优化的收益有多高？</strong> 解决了这个瓶颈，性能能提升多少？</li></ol><h3 id="第四步-小步迭代" tabindex="-1">第四步：小步迭代 <a class="header-anchor" href="#第四步-小步迭代" aria-label="Permalink to “第四步：小步迭代”">​</a></h3><p>性能优化是一个持续的过程。建议采用小步迭代的方式：</p><ul><li>每次只做一个改动</li><li>改动前后的性能对比要有数据支撑</li><li>上线后持续监控，发现问题及时回滚</li></ul><hr><h2 id="学习路径建议" tabindex="-1">学习路径建议 <a class="header-anchor" href="#学习路径建议" aria-label="Permalink to “学习路径建议”">​</a></h2><h3 id="入门-建立性能思维" tabindex="-1">入门：建立性能思维 <a class="header-anchor" href="#入门-建立性能思维" aria-label="Permalink to “入门：建立性能思维”">​</a></h3><p>建议从<strong>核心思想</strong>和<strong>度量指标</strong>开始，先建立正确的性能思维。</p><p>很多人优化了半天发现方向错了，就是因为缺乏方法论的指导。先学会如何测量、如何评估性能，比盲目优化更重要。</p><h3 id="进阶-掌握分析方法" tabindex="-1">进阶：掌握分析方法 <a class="header-anchor" href="#进阶-掌握分析方法" aria-label="Permalink to “进阶：掌握分析方法”">​</a></h3><p>深入学习<strong>瓶颈分析</strong>方法论，掌握 CPU、内存、IO、网络瓶颈的识别技巧。</p><p>这部分内容需要结合实际案例，建议在工作中遇到性能问题时，边实践边学习。</p><h3 id="高级-全链路压测" tabindex="-1">高级：全链路压测 <a class="header-anchor" href="#高级-全链路压测" aria-label="Permalink to “高级：全链路压测”">​</a></h3><p>掌握<strong>全链路压测</strong>技术，能够独立设计压测方案，评估系统容量。</p><p>全链路压测是性能优化的终极武器，也是高级工程师的必备技能。</p><hr><h2 id="延伸思考" tabindex="-1">延伸思考 <a class="header-anchor" href="#延伸思考" aria-label="Permalink to “延伸思考”">​</a></h2><p>方法论是通用的，但每个系统的具体情况不同。</p><p>同样是数据库瓶颈，一个日活百万的电商系统和一个日活千万的社交系统，优化的侧重点可能完全不同。</p><p>学习方法论，不是让你死搬硬套，而是让你有一套思考框架。在面对具体问题时，能够有条不紊地分析、定位、解决。</p><p><strong>记住：磨刀不误砍柴工。花时间学习方法论，是性价比最高的投资。</strong></p><p>下一模块，我们将深入探讨数据库性能优化——这是大多数系统最常见的瓶颈来源。</p>',47)])])}const b=a(h,[["render",i]]);export{m as __pageData,b as default};
